import Particles from "react-tsparticles";

export default function LogisticsParticles() {

  const options = {

    fullScreen: {
      enable: true,
      zIndex: -1
    },

    background: {
      color: "#f4fff1"
    },

    particles: {

      number: {
        value: 60
      },

      color: {
        value: "#7ddf64"
      },

      links: {
        enable: true,
        distance: 150,
        color: "#c7fab6",
        opacity: 0.5
      },

      move: {
        enable: true,
        speed: 1.5
      },

      shape: {
        type: "circle"
      },

      size: {
        value: 4
      }

    },

    interactivity: {

      events: {

        onHover: {
          enable: true,
          mode: "grab"
        },

        onClick: {
          enable: true,
          mode: "push"
        }

      }

    }

  };

  return <Particles options={options} />;
}
